/* == EXEMPLE ================================================
 * Inversion de 4 bits: 1010 → 0101
 * =========================================================== */
void example_reverse(void) {
    unsigned char x = 0x0A; /* 1010b */
    unsigned char r = 0;
    for (int i = 0; i < 4; i++) {
        r <<= 1;
        r |= (x & 1);
        x >>= 1;
    }
    printf("0x%X → 0x%X\n", 0x0A, r); /* 0xA → 0x5 */
}

